  ('aboriginal-7fec267e-moex-00462', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-110-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '關於行政契約之敘述，下列何者錯誤？', '["私人之間亦得締結行政契約，惟須有法律授予私人享有公法上權利義務之處分權", "私人之間亦得締結行政契約，但並不能直接適用行政程序法有關行政契約之規定", "經授與公權力之私人，得與私人締結行政契約，此即屬私人間之行政契約的適例", "經授與公權力之私人，得與私人締結行政契約，此時該契約有行政程序法之適用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:03+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00463', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-110-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '關於陳情之敘述，下列何者錯誤？', '["陳情案雖未具住址者，機關仍應予以處理", "陳情得以言詞為之", "人民得以陳情為行政法令之查詢", "受理機關認為陳情無理由者，應通知當事人，並說明理由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:03+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL)
